/**
 * Real chokepoint-transit scenarios for the port congestion replay example.
 *
 * Everything here derives from IMF PortWatch's AIS-derived daily container
 * transit counts (see portwatchChokepointDaily.js, regenerated by
 * fetchPortwatchData.mjs). Three historical windows are replayed: a quiet
 * spring, the Ever Given grounding, and the Red Sea diversion crisis.
 */
import {
  PORTWATCH_ATTRIBUTION,
  PORTWATCH_CHOKEPOINT_NAMES,
  PORTWATCH_FETCHED_AT,
  PORTWATCH_WINDOWS,
} from "./portwatchChokepointDaily"

export { PORTWATCH_ATTRIBUTION, PORTWATCH_FETCHED_AT }

const DAY = 24 * 60 * 60 * 1000
const HALF_DAY = DAY / 2
const SANKEY_BUCKET_DAYS = 3

function dateMs(iso) {
  return Date.parse(`${iso}T00:00:00Z`)
}

