const SCENARIO_BY_ID = new Map(PORT_SCENARIOS.map((s) => [s.id, s]))

function windowFor(scenarioId) {
  const window = PORTWATCH_WINDOWS[scenarioId]
  if (!window) throw new Error(`Unknown scenario "${scenarioId}"`)
  return window
}

export function scenarioById(scenarioId) {
  return SCENARIO_BY_ID.get(scenarioId)
}

export function scenarioDays(scenarioId) {
  return windowFor(scenarioId).days
}

function visibleStartMs(scenarioId) {
  const window = windowFor(scenarioId)
  return dateMs(window.start) + window.lead * DAY
}

/** Raw container-ship transits at a gate on a replay day (0-based). */
export function transitsAt(scenarioId, gateId, dayIndex) {
  const window = windowFor(scenarioId)
  const series = window.series[gateId]
  if (!series) throw new Error(`Unknown gate "${gateId}"`)
  const index = Math.min(window.lead + dayIndex, series.transits.length - 1)
  return series.transits[Math.max(window.lead, index)]
}

/** Trailing 7-day mean ending on a replay day — the lead-in supplies history. */
function trailingWeekMean(scenarioId, gateId, dayIndex) {
  const window = windowFor(scenarioId)
  const series = window.series[gateId].transits
  const end = window.lead + Math.min(dayIndex, window.days - 1)
  const start = end - 6
  let sum = 0
  for (let index = start; index <= end; index += 1) sum += series[index]
  return Math.round((sum / 7) * 10) / 10
}

/** Mean of the 7 lead-in days — each scenario's own pre-event pace. */
export function baselineFor(scenarioId, gateId) {
  const window = windowFor(scenarioId)
  const series = window.series[gateId].transits
  let sum = 0
  for (let index = 0; index < window.lead; index += 1) sum += series[index]
  return Math.round((sum / window.lead) * 10) / 10
}

export function gateName(gateId) {
  return PORTWATCH_CHOKEPOINT_NAMES[gateId] || gateId
}

