export function replayTimeForCursor(scenarioId, cursor) {
  const start = visibleStartMs(scenarioId)
  if (cursor <= 0) return start - DAY
  return start + (Math.min(cursor, scenarioDays(scenarioId)) - 1) * DAY + HALF_DAY
}

function dayIndexForTime(scenarioId, time) {
  return Math.floor((time - visibleStartMs(scenarioId)) / DAY)
}

/**
 * Map legs at the replay cursor. Width value = trailing 7-day mean of real
 * daily container-ship transits at the gate each leg crosses.
 */
export function flowsAtTime(scenarioId, time, corridorId = null) {
  const dayIndex = dayIndexForTime(scenarioId, time)
  if (dayIndex < 0) return []

  return PORT_CORRIDORS.filter(
    (corridor) => !corridorId || corridor.id === corridorId
  ).flatMap((corridor) =>
    corridor.legs.map((leg, legIndex) => {
      const sourceLocation = LOCATION_BY_ID.get(leg.source)
      const targetLocation = LOCATION_BY_ID.get(leg.target)
      return {
        id: `${scenarioId}-${corridor.id}-leg-${legIndex}`,
        corridorId: corridor.id,
        corridor: corridor.label,
        color: corridor.color,
        source: leg.source,
        target: leg.target,
        sourceName: sourceLocation?.name || leg.source,
        targetName: targetLocation?.name || leg.target,
        legIndex,
        gate: leg.gate,
        gateName: gateName(leg.gate),
        value: trailingWeekMean(scenarioId, leg.gate, dayIndex),
        today: transitsAt(scenarioId, leg.gate, dayIndex),
      }
    })
  )
}

