const sankeyEdgeCache = new Map()

/**
 * The full temporal-sankey edge set for a scenario: each stream is bucketed
 * into 3-day ribbons whose value is the summed real transit count at the
 * downstream gate over that bucket.
 */
export function sankeyEdgesFor(scenarioId) {
  if (sankeyEdgeCache.has(scenarioId)) return sankeyEdgeCache.get(scenarioId)

  const days = scenarioDays(scenarioId)
  const start = visibleStartMs(scenarioId)
  const corridorById = new Map(PORT_CORRIDORS.map((c) => [c.id, c]))
  const edges = []

  for (let bucketStart = 0; bucketStart < days; bucketStart += SANKEY_BUCKET_DAYS) {
    const bucketEnd = Math.min(bucketStart + SANKEY_BUCKET_DAYS, days)
    for (const stream of SANKEY_STREAMS) {
      const corridor = corridorById.get(stream.corridorId)
      let value = 0
      for (let day = bucketStart; day < bucketEnd; day += 1) {
        value += transitsAt(scenarioId, stream.gate, day)
      }
      edges.push({
        id: `${scenarioId}-${stream.gate}-b${bucketStart}`,
        source: stream.source,
        target: stream.target,
        startTime: start + bucketStart * DAY,
        endTime: start + bucketEnd * DAY,
        value,
        corridorId: stream.corridorId,
        corridor: corridor.label,
        category: corridor.label,
        gate: stream.gate,
        gateName: gateName(stream.gate),
        bucketDays: bucketEnd - bucketStart,
      })
    }
  }

  sankeyEdgeCache.set(scenarioId, edges)
  return edges
}

export function processEdgesAtTime(scenarioId, time, corridorId = null) {
  return sankeyEdgesFor(scenarioId)
    .filter(
      (edge) =>
        edge.startTime <= time &&
        (!corridorId || edge.corridorId === corridorId)
    )
    .map((edge) => ({
      ...edge,
      endTime: Math.max(
        edge.startTime + 60 * 1000,
        Math.min(edge.endTime, time)
      ),
    }))
}

/** The waterfall's gate: an explicit corridor pick wins, else the scenario focal. */
export function gateForSelection(scenarioId, corridorId = null) {
  if (corridorId) {
    const corridor = PORT_CORRIDORS.find((c) => c.id === corridorId)
    if (corridor) return corridor.gate
  }
  return scenarioById(scenarioId).focal
}

const waterfallCache = new Map()

/**
 * Daily deviation from the scenario's own pre-event pace at one gate.
 * Bars are (actual − baseline) ships/day, so the cumulative waterfall level
 * reads as "transits behind (or ahead of) normal pace since the window began"
 * — during the Ever Given blockage that running deficit is, physically, the
 * queue forming at anchor.
 */
export function waterfallSeriesFor(scenarioId, gateId) {
  const key = `${scenarioId}:${gateId}`
  if (waterfallCache.has(key)) return waterfallCache.get(key)

  const days = scenarioDays(scenarioId)
  const start = visibleStartMs(scenarioId)
  const baseline = baselineFor(scenarioId, gateId)
  const series = []
  for (let day = 0; day < days; day += 1) {
    const actual = transitsAt(scenarioId, gateId, day)
    series.push({
      id: `wf-${scenarioId}-${gateId}-${day}`,
      time: start + day * DAY + HALF_DAY,
      value: Math.round((actual - baseline) * 10) / 10,
      actual,
      baseline,
      gate: gateId,
      gateName: gateName(gateId),
      dayIndex: day,
    })
  }

  waterfallCache.set(key, series)
  return series
}

/** Cumulative deviation from baseline pace through a replay day. */
export function cumulativeDeviation(scenarioId, gateId, throughDay) {
  const series = waterfallSeriesFor(scenarioId, gateId)
  let sum = 0
  for (const row of series) {
    if (row.dayIndex > throughDay) break
    sum += row.value
  }
  return Math.round(sum * 10) / 10
}

export const PORT_MATRIX_FIELDS = [
  "suez",
  "babElMandeb",
  "capeOfGoodHope",
  "panama",
]

export const PORT_MATRIX_FIELD_LABELS = {
  suez: "Suez / day",
  babElMandeb: "Bab el-Mandeb / day",
  capeOfGoodHope: "Cape / day",
  panama: "Panama / day",
}

/**
 * One row per replayed day across all three scenarios — the scatterplot
 * matrix always shows every scenario so the selected one can be read against
 * the other two. Rows are grouped in PORT_SCENARIOS order so colorBy keeps a
 * stable category→color assignment.
 */
export const PORT_MATRIX_ROWS = PORT_SCENARIOS.flatMap((scenario) => {
  const days = scenarioDays(scenario.id)
  const start = visibleStartMs(scenario.id)
  return Array.from({ length: days }, (_, day) => {
    const time = start + day * DAY
    const row = {
      id: `${scenario.id}-day-${day}`,
      scenarioId: scenario.id,
      scenario: scenario.shortLabel,
      dayIndex: day,
      time: time + HALF_DAY,
      date: new Date(time).toISOString().slice(0, 10),
      label: `${scenario.shortLabel} · ${formatPortTime(time)}`,
    }
    for (const field of PORT_MATRIX_FIELDS) {
      row[field] = transitsAt(scenario.id, field, day)
    }
    return row
  })
})

export function domainFor(scenarioId) {
  const start = visibleStartMs(scenarioId)
  return [start - DAY, start + scenarioDays(scenarioId) * DAY]
}

export function axisTicksFor(scenarioId) {
  const start = visibleStartMs(scenarioId)
  const days = scenarioDays(scenarioId)
  const ticks = []
  for (let day = 0; day <= days; day += 7) {
    const date = start + day * DAY
    ticks.push({
      date,
      label: new Intl.DateTimeFormat("en-US", {
        month: "short",
        day: "numeric",
        timeZone: "UTC",
      }).format(date),
    })
  }
  return ticks
}

/** Real-dated event markers for the waterfall's annotation layer. */
export function eventAnnotationsFor(scenarioId) {
  return scenarioById(scenarioId).events.map((event) => ({
    type: "x-threshold",
    value: dateMs(event.date) + HALF_DAY,
    label: event.label,
    color: "#ffd166",
  }))
}

export function formatPortTime(time) {
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    year: "numeric",
    timeZone: "UTC",
  }).format(time)
}

export function formatPortDay(time) {
  return new Intl.DateTimeFormat("en-US", {
    month: "short",
    day: "numeric",
    timeZone: "UTC",
  }).format(time)
}
